/* ---------------------------------------------------------------------------
 * transitions.css — suite 14/P06
 * Subtle cross-page fade. Opacity-only, no transform travel. Reduced-motion
 * users get the static end-state. Zero JS bytes; pure CSS animation.
 * --------------------------------------------------------------------------- */

.page-transition {
  animation: page-in var(--d-norm) var(--ease-out) forwards;
}

@keyframes page-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

@media (prefers-reduced-motion: reduce) {
  .page-transition { animation: none; }
}

